#include <bits/stdc++.h>

using namespace std;

using ll = long long;

int const MOD = 998244353;

int add(int x, int y) {
    x += y;
    if (x >= MOD) {
        x -= MOD;
    }
    return x;
}

void add_self(int& x, int y) {
    x = add(x, y);
}

int sub(int x, int y) {
    x -= y;
    if (x < 0) {
        x += MOD;
    }
    return x;
}

int mul(ll x, int y) {
    return int(x * y % MOD);
}

int power(int x, int d) {
    int res = 1;
    while (d) {
        if (d & 1) {
            res = mul(res, x);
        }
        x = mul(x, x);
        d /= 2;
    }
    return res;
}

int inv(int x) {
    return power(x, MOD - 2);
}

vector<vector<string>> by_digit{
    {"I", "II", "III", "IV", "V", "VI", "VII", "VIII", "IX"},
    {"X", "XX", "XXX", "XL", "L", "LX", "LXX", "LXXX", "XC"},
    {"C", "CC", "CCC", "CD", "D", "DC", "DCC", "DCCC", "CM"},
    {"M", "MM", "MMM"}
};

string const digits = "IVXLCDM";

vector<int> powers{1, 10, 100, 1000};

string roman_to_string(int n) {
    string res;
    for (int d = 3; d >= 0; --d) {
        int dig = n / powers[d] % 10;
        if (dig > 0) {
            res += by_digit[d][dig - 1];
        }
    }
    return res;
}

void precalc() {
    int const N = 4000;
    vector<string> strs(N);
    map<string, int> str_to_num;
    for (int num = 1; num < N; ++num) {
        strs[num] = roman_to_string(num);
        str_to_num[strs[num]] = num;
    }

    vector<vector<int>> transitions(N);

    for (int cur_num = 1; cur_num < N; ++cur_num) {
        string cur_string = strs[cur_num];
        for (char d : digits) {
            string new_string = cur_string + d;
            while (!str_to_num.count(new_string)) {
                new_string = new_string.substr(1);
            }
            transitions[cur_num].push_back(str_to_num[new_string]);
        }
    }
    
    int const LEN = 1000;
    int const MAX_ANS = 15;
    vector dp(N, vector<int>(MAX_ANS + 1, 0));
    dp[1][1] = 1;
    dp[5][1] = 1;
    dp[10][1] = 1;
    dp[50][1] = 1;
    dp[100][1] = 1;
    dp[500][1] = 1;
    dp[1000][1] = 1;
    vector<int> answers(LEN + 1);
    for (int len = 1; len <= LEN; ++len) {
        for (int cur_end = 0; cur_end < N; ++cur_end) {
            for (int cur_ans = 0; cur_ans <= MAX_ANS; ++cur_ans) {
                answers[len] = add(answers[len], mul(dp[cur_end][cur_ans], cur_ans));
            }
        }

        vector ndp(N, vector<int>(MAX_ANS + 1, 0));
        for (int cur_end = 0; cur_end < N; ++cur_end) {
            for (int cur_ans = 0; cur_ans <= MAX_ANS; ++cur_ans) {
                int val = dp[cur_end][cur_ans];
                if (val == 0) {
                    continue;
                }

                for (int new_end : transitions[cur_end]) {
                    add_self(ndp[new_end][max(cur_ans, int(strs[new_end].size()))], val);
                }
            }
        }

        dp = ndp;
    }

    int i7 = inv(7);

    int ipower = 1;
    for (int i = 1; i <= LEN; ++i) {
        ipower = mul(ipower, i7);
        answers[i] = mul(answers[i], ipower);
    }
    for (int len = 1; len <= LEN; ++len) {
        if (len > 1) {
            cout << ",";
        }
        cout << answers[len];
    }
}

